import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, onClose }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const isAdmin = user.role === 'admin';

  const menuItems = [
    { icon: '📊', label: 'Dashboard', path: '/dashboard' },
    { icon: '📁', label: 'Projects', path: '/dashboard' },
    { icon: '📋', label: 'My Tasks', path: '/dashboard' },
    { icon: '🔔', label: 'Notifications', path: '/dashboard' },
    // 👇 Admin menu - only visible to admin users
    ...(isAdmin ? [{ icon: '🔐', label: 'Admin Panel', path: '/admin' }] : []),
    { icon: '⚙️', label: 'Settings', path: '/settings' },
  ];

  const handleNavigation = (path: string) => {
    navigate(path);
    onClose();
  };

  return (
    <>
      {/* Overlay */}
      {isOpen && (
        <div
          onClick={onClose}
          style={styles.overlay}
        />
      )}

      {/* Sidebar */}
      <div style={{
        ...styles.sidebar,
        transform: isOpen ? 'translateX(0)' : 'translateX(-100%)'
      }}>
        <div style={styles.header}>
          <h2 style={styles.logo}>📊 TeamFlow</h2>
          <button onClick={onClose} style={styles.closeBtn}>✕</button>
        </div>

        {/* User info */}
        <div style={styles.userCard}>
          <div style={styles.userAvatar}>👤</div>
          <div>
            <div style={styles.userName}>{user.name || 'Guest'}</div>
            <div style={styles.userRole}>
              {user.role ? `🔑 ${user.role.replace('_', ' ')}` : 'No role'}
            </div>
          </div>
        </div>

        <nav style={styles.nav}>
          {menuItems.map((item) => (
            <div
              key={item.path}
              onClick={() => handleNavigation(item.path)}
              style={{
                ...styles.navItem,
                backgroundColor: location.pathname === item.path ? '#2a2a4e' : 'transparent'
              }}
            >
              <span style={styles.navIcon}>{item.icon}</span>
              <span>{item.label}</span>
              {item.label === 'Admin Panel' && (
                <span style={styles.adminBadge}>🔐</span>
              )}
            </div>
          ))}
        </nav>

        <div style={styles.bottom}>
          <div style={styles.version}>v1.0.0</div>
        </div>
      </div>
    </>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  overlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0,0,0,0.5)',
    zIndex: 999
  },
  sidebar: {
    position: 'fixed',
    top: 0,
    left: 0,
    bottom: 0,
    width: '280px',
    backgroundColor: '#1a1a2e',
    color: 'white',
    zIndex: 1000,
    transition: 'transform 0.3s ease',
    display: 'flex',
    flexDirection: 'column' as 'column'
  },
  header: {
    padding: '20px',
    borderBottom: '1px solid #333',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  logo: {
    margin: 0,
    fontSize: '20px'
  },
  closeBtn: {
    background: 'none',
    border: 'none',
    color: 'white',
    fontSize: '20px',
    cursor: 'pointer'
  },
  userCard: {
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    padding: '15px 20px',
    backgroundColor: '#2a2a4e',
    margin: '10px',
    borderRadius: '8px'
  },
  userAvatar: {
    fontSize: '24px'
  },
  userName: {
    fontSize: '14px',
    fontWeight: 'bold'
  },
  userRole: {
    fontSize: '11px',
    opacity: 0.7
  },
  nav: {
    flex: 1,
    padding: '10px 0'
  },
  navItem: {
    padding: '12px 20px',
    display: 'flex',
    alignItems: 'center',
    gap: '15px',
    cursor: 'pointer',
    transition: 'background 0.2s',
    borderRadius: '8px',
    margin: '4px 10px'
  },
  navIcon: {
    fontSize: '20px'
  },
  adminBadge: {
    marginLeft: 'auto',
    fontSize: '14px'
  },
  bottom: {
    padding: '20px',
    borderTop: '1px solid #333'
  },
  version: {
    fontSize: '12px',
    color: '#666',
    textAlign: 'center' as 'center'
  }
};

export default Sidebar;
